import{_ as e,c as o,m as t,a as i,t as r,a5 as s,o as n}from"./chunks/framework.DwbewbAn.js";const q=JSON.parse('{"title":"ACID特性","description":"","frontmatter":{"title":"ACID特性"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/事务/ACID特性.md","filePath":"packages/doc/src/数据库/Mysql/基础/事务/ACID特性.md","lastUpdated":1711622925000}'),l={name:"doc/数据库/Mysql/基础/事务/ACID特性.md"},c={id:"frontmatter-title",tabindex:"-1"},d=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=s('<h2 id="原子性-atomicity" tabindex="-1">原子性（Atomicity） <a class="header-anchor" href="#原子性-atomicity" aria-label="Permalink to &quot;原子性（Atomicity）&quot;">​</a></h2><p>原子性是指事务包含的所有操作要么全部成功，要么全部失败回滚。</p><h2 id="一致性-consistency" tabindex="-1">一致性（Consistency） <a class="header-anchor" href="#一致性-consistency" aria-label="Permalink to &quot;一致性（Consistency）&quot;">​</a></h2><p>在事务开始之前和事务结束以后，数据库的完整性没有被破坏。这表示写入的资料必须完全符合所有的预设规则，这包含资料的精确度、串联性以及后续数据库可以自发性地完成预定的工作。 原子性、隔离性、持久性是因，一致性是果。</p><h2 id="隔离性-isolation" tabindex="-1">隔离性（Isolation） <a class="header-anchor" href="#隔离性-isolation" aria-label="Permalink to &quot;隔离性（Isolation）&quot;">​</a></h2><p>数据库允许多个并发事务同时对其数据进行读写和修改的能力，隔离性可以防止多个事务并发执行时由于交叉执行而导致数据的不一致。</p><h2 id="持久性-durability" tabindex="-1">持久性（Durability） <a class="header-anchor" href="#持久性-durability" aria-label="Permalink to &quot;持久性（Durability）&quot;">​</a></h2><p>持久性是指一个事务一旦被提交了，那么对数据库中的数据的改变就是永久性的，即便是在数据库系统遇到故障的情况下也不会丢失提交事务的操作</p>',8);function _(a,m,p,f,u,y){return n(),o("div",null,[t("h1",c,[i(r(a.$frontmatter.title)+" ",1),d]),h])}const A=e(l,[["render",_]]);export{q as __pageData,A as default};
